@startuml
' Define skinparameters for colors and styles
skinparam defaultFontName "Arial"
skinparam defaultFontSize 12
skinparam class {
    BackgroundColor White
    BorderColor Black
    ArrowColor Black
    FontColor Black
}

' Define classes and interfaces
class A {
    <<Interface>>
    void operation1()
}

class B {
    <<Interface>>
    void operation2()
    void operation3()
}

class C {
    <<Interface>>
    void operation4()
    void operation5()
}

class D {
    <<Interface>>
    void operation1()
}

' Define relationships
A --|> B
A --|> D
C --|> B
C --|> D

' Define interface symbols
interface Interface2 {
    <<Interface>>
    void operation2()
    void operation3()
}

interface Interface1 {
    <<Interface>>
    void operation1()
}

interface Interface3 {
    <<Interface>>
    void operation4()
    void operation5()
}

' Define relationships for interfaces
A --|> Interface2
A --|> Interface1
C --|> Interface1
C --|> Interface3

@enduml
